1	import {
2	  ImageModelV3,
3	  ImageModelV3CallOptions,
4	  ImageModelV3File,
5	  ImageModelV3ProviderMetadata,
6	} from '@ai-sdk/provider';
7	import {
8	  convertBase64ToUint8Array,
9	  DataContent,
10	  ProviderOptions,
11	  withUserAgentSuffix,
12	} from '@ai-sdk/provider-utils';
13	import { NoImageGeneratedError } from '../error/no-image-generated-error';
14	import {
15	  DefaultGeneratedFile,
16	  GeneratedFile,
17	} from '../generate-text/generated-file';
18	import { logWarnings } from '../logger/log-warnings';
19	import { resolveImageModel } from '../model/resolve-model';
20	import type { ImageModel } from '../types/image-model';
21	import { ImageModelResponseMetadata } from '../types/image-model-response-metadata';
22	import { addImageModelUsage, ImageModelUsage } from '../types/usage';
23	import { Warning } from '../types/warning';
24	import {
25	  detectMediaType,
26	  imageMediaTypeSignatures,
27	} from '../util/detect-media-type';
28	import { prepareRetries } from '../util/prepare-retries';
29	import { VERSION } from '../version';
30	import { GenerateImageResult } from './generate-image-result';
31	import { convertDataContentToUint8Array } from '../prompt/data-content';
32	import { splitDataUrl } from '../prompt/split-data-url';
33	
34	export type GenerateImagePrompt =
35	  | string
36	  | {
37	      images: Array<DataContent>;
38	      text?: string;
39	      mask?: DataContent;
40	    };
41	
42	/**
43	 * Generates images using an image model.
44	 *
45	 * @param model - The image model to use.
46	 * @param prompt - The prompt that should be used to generate the image.
47	 * @param n - Number of images to generate. Default: 1.
48	 * @param maxImagesPerCall - Maximum number of images to generate in a single API call.
49	 * @param size - Size of the images to generate. Must have the format `{width}x{height}`.
50	 * @param aspectRatio - Aspect ratio of the images to generate. Must have the format `{width}:{height}`.
51	 * @param seed - Seed for the image generation.
52	 * @param providerOptions - Additional provider-specific options that are passed through to the provider
53	 * as body parameters.
54	 * @param maxRetries - Maximum number of retries. Set to 0 to disable retries. Default: 2.
55	 * @param abortSignal - An optional abort signal that can be used to cancel the call.
56	 * @param headers - Additional HTTP headers to be sent with the request. Only applicable for HTTP-based providers.
57	 *
58	 * @returns A result object that contains the generated images.
59	 */
60	export async function generateImage({
61	  model: modelArg,
62	  prompt: promptArg,
63	  n = 1,
64	  maxImagesPerCall,
65	  size,
66	  aspectRatio,
67	  seed,
68	  providerOptions,
69	  maxRetries: maxRetriesArg,
70	  abortSignal,
71	  headers,
72	}: {
73	  /**
74	   * The image model to use.
75	   */
76	  model: ImageModel;
77	
78	  /**
79	   * The prompt that should be used to generate the image.
80	   */
81	  prompt: GenerateImagePrompt;
82	
83	  /**
84	   * Number of images to generate.
85	   */
86	  n?: number;
87	
88	  /**
89	   * Maximum number of images to generate in a single API call. If not provided, the model's default will be used.
90	   */
91	  maxImagesPerCall?: number;
92	
93	  /**
94	   * Size of the images to generate. Must have the format `{width}x{height}`. If not provided, the default size will be used.
95	   */
96	  size?: `${number}x${number}`;
97	
98	  /**
99	   * Aspect ratio of the images to generate. Must have the format `{width}:{height}`. If not provided, the default aspect ratio will be used.
100	   */
101	  aspectRatio?: `${number}:${number}`;
102	
103	  /**
104	   * Seed for the image generation. If not provided, the default seed will be used.
105	   */
106	  seed?: number;
107	
108	  /**
109	   * Additional provider-specific options that are passed through to the provider
110	   * as body parameters.
111	   *
112	   * The outer record is keyed by the provider name, and the inner
113	   * record is keyed by the provider-specific metadata key.
114	   * ```ts
115	   * {
116	   * "openai": {
117	   * "style": "vivid"
118	   * }
119	   * }
120	   * ```
121	   */
122	  providerOptions?: ProviderOptions;
123	
124	  /**
125	   * Maximum number of retries per image model call. Set to 0 to disable retries.
126	   *
127	   * @default 2
128	   */
129	  maxRetries?: number;
130	
131	  /**
132	   * Abort signal.
133	   */
134	  abortSignal?: AbortSignal;
135	
136	  /**
137	   * Additional headers to include in the request.
138	   * Only applicable for HTTP-based providers.
139	   */
140	  headers?: Record<string, string>;
141	}): Promise<GenerateImageResult> {
142	  const model = resolveImageModel(modelArg);
143	
144	  const headersWithUserAgent = withUserAgentSuffix(
145	    headers ?? {},
146	    `ai/${VERSION}`,
147	  );
148	
149	  const { retry } = prepareRetries({
150	    maxRetries: maxRetriesArg,
151	    abortSignal,
152	  });
153	
154	  // default to 1 if the model has not specified limits on
155	  // how many images can be generated in a single call
156	  const maxImagesPerCallWithDefault =
157	    maxImagesPerCall ?? (await invokeModelMaxImagesPerCall(model)) ?? 1;
158	
159	  // parallelize calls to the model:
160	  const callCount = Math.ceil(n / maxImagesPerCallWithDefault);
161	  const callImageCounts = Array.from({ length: callCount }, (_, i) => {
162	    if (i < callCount - 1) {
163	      return maxImagesPerCallWithDefault;
164	    }
165	
166	    const remainder = n % maxImagesPerCallWithDefault;
167	    return remainder === 0 ? maxImagesPerCallWithDefault : remainder;
168	  });
169	
170	  const results = await Promise.all(
171	    callImageCounts.map(async callImageCount =>
172	      retry(() => {
173	        const { prompt, files, mask } = normalizePrompt(promptArg);
174	
175	        return model.doGenerate({
176	          prompt,
177	          files,
178	          mask,
179	          n: callImageCount,
180	          abortSignal,
181	          headers: headersWithUserAgent,
182	          size,
183	          aspectRatio,
184	          seed,
185	          providerOptions: providerOptions ?? {},
186	        });
187	      }),
188	    ),
189	  );
190	
191	  // collect result images, warnings, and response metadata
192	  const images: Array<DefaultGeneratedFile> = [];
193	  const warnings: Array<Warning> = [];
194	  const responses: Array<ImageModelResponseMetadata> = [];
195	  const providerMetadata: ImageModelV3ProviderMetadata = {};
196	  let totalUsage: ImageModelUsage = {
197	    inputTokens: undefined,
198	    outputTokens: undefined,
199	    totalTokens: undefined,
200	  };
201	  for (const result of results) {
202	    images.push(
203	      ...result.images.map(
204	        image =>
205	          new DefaultGeneratedFile({
206	            data: image,
207	            mediaType:
208	              detectMediaType({
209	                data: image,
210	                signatures: imageMediaTypeSignatures,
211	              }) ?? 'image/png',
212	          }),
213	      ),
214	    );
215	    warnings.push(...result.warnings);
216	
217	    if (result.usage != null) {
218	      totalUsage = addImageModelUsage(totalUsage, result.usage);
219	    }
220	
221	    if (result.providerMetadata) {
222	      for (const [providerName, metadata] of Object.entries<{
223	        images: unknown;
224	      }>(result.providerMetadata)) {
225	        if (providerName === 'gateway') {
226	          const currentEntry = providerMetadata[providerName];
227	          if (currentEntry != null && typeof currentEntry === 'object') {
228	            providerMetadata[providerName] = {
229	              ...(currentEntry as object),
230	              ...metadata,
231	            } as ImageModelV3ProviderMetadata[string];
232	          } else {
233	            providerMetadata[providerName] =
234	              metadata as ImageModelV3ProviderMetadata[string];
235	          }
236	          const imagesValue = (
237	            providerMetadata[providerName] as { images?: unknown }
238	          ).images;
239	          if (Array.isArray(imagesValue) && imagesValue.length === 0) {
240	            delete (providerMetadata[providerName] as { images?: unknown })
241	              .images;
242	          }
243	        } else {
244	          providerMetadata[providerName] ??= { images: [] };
245	          providerMetadata[providerName].images.push(
246	            ...result.providerMetadata[providerName].images,
247	          );
248	        }
249	      }
250	    }
251	
252	    responses.push(result.response);
253	  }
254	
255	  logWarnings({ warnings, provider: model.provider, model: model.modelId });
256	
257	  if (!images.length) {
258	    throw new NoImageGeneratedError({ responses });
259	  }
260	
261	  return new DefaultGenerateImageResult({
262	    images,
263	    warnings,
264	    responses,
265	    providerMetadata,
266	    usage: totalUsage,
267	  });
268	}
269	
270	class DefaultGenerateImageResult implements GenerateImageResult {
271	  readonly images: Array<GeneratedFile>;
272	  readonly warnings: Array<Warning>;
273	  readonly responses: Array<ImageModelResponseMetadata>;
274	  readonly providerMetadata: ImageModelV3ProviderMetadata;
275	  readonly usage: ImageModelUsage;
276	
277	  constructor(options: {
278	    images: Array<GeneratedFile>;
279	    warnings: Array<Warning>;
280	    responses: Array<ImageModelResponseMetadata>;
281	    providerMetadata: ImageModelV3ProviderMetadata;
282	    usage: ImageModelUsage;
283	  }) {
284	    this.images = options.images;
285	    this.warnings = options.warnings;
286	    this.responses = options.responses;
287	    this.providerMetadata = options.providerMetadata;
288	    this.usage = options.usage;
289	  }
290	
291	  get image() {
292	    return this.images[0];
293	  }
294	}
295	
296	async function invokeModelMaxImagesPerCall(model: ImageModelV3) {
297	  const isFunction = model.maxImagesPerCall instanceof Function;
298	
299	  if (!isFunction) {
300	    return model.maxImagesPerCall;
301	  }
302	
303	  return model.maxImagesPerCall({
304	    modelId: model.modelId,
305	  });
306	}
307	
308	function normalizePrompt(
309	  prompt: GenerateImagePrompt,
310	): Pick<ImageModelV3CallOptions, 'prompt' | 'files' | 'mask'> {
311	  if (typeof prompt === 'string') {
312	    return { prompt, files: undefined, mask: undefined };
313	  }
314	
315	  return {
316	    prompt: prompt.text,
317	    files: prompt.images.map(toImageModelV3File),
318	    mask: prompt.mask ? toImageModelV3File(prompt.mask) : undefined,
319	  };
320	}
321	
322	function toImageModelV3File(dataContent: DataContent): ImageModelV3File {
323	  if (typeof dataContent === 'string' && dataContent.startsWith('http')) {
324	    return {
325	      type: 'url',
326	      url: dataContent,
327	    };
328	  }
329	
330	  // Handle data URLs
331	  if (typeof dataContent === 'string' && dataContent.startsWith('data:')) {
332	    const { mediaType: dataUrlMediaType, base64Content } =
333	      splitDataUrl(dataContent);
334	
335	    if (base64Content != null) {
336	      const uint8Data = convertBase64ToUint8Array(base64Content);
337	      return {
338	        type: 'file',
