## 8. How generateImage() Works

**Location:** `/packages/ai/src/generate-image/generate-image.ts`

The SDK orchestrates parallel calls to your model:

```typescript
export async function generateImage({
  model: modelArg,
  prompt: promptArg,
  n = 1,                    // Total images to generate
  maxImagesPerCall,         // Override model's limit
  size,
  aspectRatio,
  seed,
  providerOptions,
  maxRetries = 2,
  abortSignal,
  headers,
}: GenerateImageOptions): Promise<GenerateImageResult> {
  const model = resolveImageModel(modelArg);

  const maxImagesPerCallWithDefault =
    maxImagesPerCall ?? (await invokeModelMaxImagesPerCall(model)) ?? 1;

  // Parallelize calls if requesting more images than maxImagesPerCall allows
  const callCount = Math.ceil(n / maxImagesPerCallWithDefault);
  const callImageCounts = Array.from({ length: callCount }, (_, i) => {
    if (i < callCount - 1) {
      return maxImagesPerCallWithDefault;
    }
    const remainder = n % maxImagesPerCallWithDefault;
    return remainder === 0 ? maxImagesPerCallWithDefault : remainder;
  });

  // Make parallel API calls
  const results = await Promise.all(
    callImageCounts.map(async callImageCount =>
      retry(() => {
        const { prompt, files, mask } = normalizePrompt(promptArg);
        return model.doGenerate({
          prompt,
          files,
          mask,
          n: callImageCount,
          abortSignal,
          headers: headersWithUserAgent,
          size,
          aspectRatio,
          seed,
          providerOptions: providerOptions ?? {},
        });
      }),
    ),
  );

  // Aggregate results, warnings, metadata, and usage
  // ...
}
