```typescript
export class LumaImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;
  readonly pollIntervalMillis = 500;
  readonly maxPollAttempts = 120;

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }): Promise<...> {
    // 1. Parse provider options
    const lumaOptions = await parseProviderOptions({
      provider: 'luma',
      providerOptions,
      schema: lumaImageModelOptionsSchema,
    });

    // 2. Make API call (POST JSON)
    const { value: generationResponse } = await postJsonToApi({
      url: this.getLumaGenerationsUrl(),
      headers: combineHeaders(this.config.headers(), headers),
      body: { prompt, model: this.modelId, ...options },
      failedResponseHandler: createJsonErrorResponseHandler({...}),
      successfulResponseHandler: createJsonResponseHandler(schema),
      fetch: this.config.fetch,
    });

    // 3. Poll for completion (GET)
    const imageUrl = await this.pollForImageUrl(...);

    // 4. Download image binary (GET with binary handler)
    const downloadedImage = await getFromApi({
      url: imageUrl,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
    });

    // 5. Return standardized response
    return {
      images: [downloadedImage],
      warnings: [...],
      response: { modelId, timestamp, headers },
    };
  }
}
