### 7. **Factory Pattern: src/anthropic-provider.ts**

This is the core pattern for provider creation:

```typescript
// Type-safe model IDs using union types
export type AnthropicMessagesModelId =
  | 'claude-3-haiku-20240307'
  | 'claude-haiku-4-5-20251001'
  | 'claude-opus-4-5'
  | 'claude-sonnet-4-5'
  | (string & {});  // Allow custom model strings

// Configuration settings
export interface AnthropicProviderSettings {
  baseURL?: string;
  apiKey?: string;
  authToken?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  generateId?: () => string;
  name?: string;
}

// Provider interface with callable signature + methods
export interface AnthropicProvider extends ProviderV3 {
  // Callable: anthropic('model-id')
  (modelId: AnthropicMessagesModelId): LanguageModelV3;

  // Methods with same behavior
  languageModel(modelId: AnthropicMessagesModelId): LanguageModelV3;
  chat(modelId: AnthropicMessagesModelId): LanguageModelV3;
  messages(modelId: AnthropicMessagesModelId): LanguageModelV3;

  // Provider-specific tools
  tools: typeof anthropicTools;
}

// Factory function: creates configured provider instance
export function createAnthropic(
  options: AnthropicProviderSettings = {},
): AnthropicProvider {
  // 1. Resolve base URL from options or env vars
  const baseURL = 
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'ANTHROPIC_BASE_URL',
      }),
    ) ?? 'https://api.anthropic.com/v1';

  const providerName = options.name ?? 'anthropic.messages';

  // 2. Setup authentication headers
  const getHeaders = () => {
    const authHeaders = options.authToken
      ? { Authorization: `Bearer ${options.authToken}` }
      : {
          'x-api-key': loadApiKey({
            apiKey: options.apiKey,
            environmentVariableName: 'ANTHROPIC_API_KEY',
            description: 'Anthropic',
          }),
        };

    return withUserAgentSuffix(
      {
        'anthropic-version': '2023-06-01',
        ...authHeaders,
        ...options.headers,
      },
      `ai-sdk/anthropic/${VERSION}`,
    );
  };

  // 3. Create factory for language models
  const createChatModel = (modelId: AnthropicMessagesModelId) =>
    new AnthropicMessagesLanguageModel(modelId, {
      provider: providerName,
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
      generateId: options.generateId ?? generateId,
      supportedUrls: () => ({
        'image/*': [/^https?:\/\/.*$/],
        'application/pdf': [/^https?:\/\/.*$/],
      }),
    });

  // 4. Create provider object with callable signature
  const provider = function (modelId: AnthropicMessagesModelId) {
    if (new.target) {
      throw new Error('Cannot be called with new keyword.');
    }
    return createChatModel(modelId);
  };

  // 5. Add v3 spec and methods
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.messages = createChatModel;

  provider.embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };
  provider.imageModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'imageModel' });
  };

  provider.tools = anthropicTools;

  return provider;
}

// 6. Export singleton instance
export const anthropic = createAnthropic();
```

