    dts: true,
    sourcemap: true
  }
]);
```

---

### 6. **Main Entry Point: src/index.ts**

The entry point uses **selective re-exports**:

```typescript
// Type exports
export type {
  AnthropicMessageMetadata,
  AnthropicLanguageModelOptions,
  AnthropicProviderOptions
} from './anthropic-messages-options';

// Provider function and interface
export { anthropic, createAnthropic } from './anthropic-provider';
export type { AnthropicProvider, AnthropicProviderSettings } from './anthropic-provider';

// Utilities
export { forwardAnthropicContainerIdFromLastStep } from './forward-anthropic-container-id-from-last-step';
export { VERSION } from './version';
```

---

### 7. **Factory Pattern: src/anthropic-provider.ts**

This is the core pattern for provider creation:

```typescript
// Type-safe model IDs using union types
export type AnthropicMessagesModelId =
  | 'claude-3-haiku-20240307'
  | 'claude-haiku-4-5-20251001'
  | 'claude-opus-4-5'
  | 'claude-sonnet-4-5'
  | (string & {});  // Allow custom model strings

// Configuration settings
export interface AnthropicProviderSettings {
  baseURL?: string;
  apiKey?: string;
  authToken?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  generateId?: () => string;
  name?: string;
}

// Provider interface with callable signature + methods
export interface AnthropicProvider extends ProviderV3 {
  // Callable: anthropic('model-id')
  (modelId: AnthropicMessagesModelId): LanguageModelV3;

  // Methods with same behavior
  languageModel(modelId: AnthropicMessagesModelId): LanguageModelV3;
  chat(modelId: AnthropicMessagesModelId): LanguageModelV3;
  messages(modelId: AnthropicMessagesModelId): LanguageModelV3;

  // Provider-specific tools
  tools: typeof anthropicTools;
}

// Factory function: creates configured provider instance
export function createAnthropic(
  options: AnthropicProviderSettings = {},
): AnthropicProvider {
  // 1. Resolve base URL from options or env vars
  const baseURL = 
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'ANTHROPIC_BASE_URL',
      }),
    ) ?? 'https://api.anthropic.com/v1';

  const providerName = options.name ?? 'anthropic.messages';

  // 2. Setup authentication headers
  const getHeaders = () => {
    const authHeaders = options.authToken
      ? { Authorization: `Bearer ${options.authToken}` }
      : {
          'x-api-key': loadApiKey({
            apiKey: options.apiKey,
            environmentVariableName: 'ANTHROPIC_API_KEY',
            description: 'Anthropic',
          }),
        };

    return withUserAgentSuffix(
      {
        'anthropic-version': '2023-06-01',
        ...authHeaders,
        ...options.headers,
      },
      `ai-sdk/anthropic/${VERSION}`,
    );
  };

  // 3. Create factory for language models
  const createChatModel = (modelId: AnthropicMessagesModelId) =>
    new AnthropicMessagesLanguageModel(modelId, {
      provider: providerName,
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
      generateId: options.generateId ?? generateId,
      supportedUrls: () => ({
        'image/*': [/^https?:\/\/.*$/],
        'application/pdf': [/^https?:\/\/.*$/],
      }),
    });

  // 4. Create provider object with callable signature
  const provider = function (modelId: AnthropicMessagesModelId) {
    if (new.target) {
      throw new Error('Cannot be called with new keyword.');
    }
    return createChatModel(modelId);
  };

  // 5. Add v3 spec and methods
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.messages = createChatModel;

  provider.embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };
  provider.imageModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'imageModel' });
  };

  provider.tools = anthropicTools;

  return provider;
}

// 6. Export singleton instance
export const anthropic = createAnthropic();
```

**Usage Pattern**:
```typescript
import { anthropic, createAnthropic } from '@ai-sdk/anthropic';

// Default instance
const model1 = anthropic('claude-3-haiku-20240307');

// Custom instance with options
const customProvider = createAnthropic({
  baseURL: 'https://custom-proxy.example.com/v1',
  apiKey: 'custom-key',
  headers: { 'X-Custom-Header': 'value' }
});
const model2 = customProvider('claude-opus-4-5');
```

---

### 8. **Provider Interface Contract (ProviderV3)**

**Location**: `/packages/provider/src/provider/v3/provider-v3.ts`

```typescript
export interface ProviderV3 {
  readonly specificationVersion: 'v3';

  // Language model generation
  languageModel(modelId: string): LanguageModelV3;

  // Text embedding (optional)
  embeddingModel(modelId: string): EmbeddingModelV3;
  textEmbeddingModel?(modelId: string): EmbeddingModelV3;

  // Image generation (optional)
  imageModel(modelId: string): ImageModelV3;

  // Speech, transcription, etc. (optional)
  speechModel?(modelId: string): SpeechModelV3;
  transcriptionModel?(modelId: string): TranscriptionModelV3;
  rerankingModel?(modelId: string): RerankingModelV3;
}
```

---

### 9. **Language Model Interface (LanguageModelV3)**

**Location**: `/packages/provider/src/language-model/v3/language-model-v3.ts`

```typescript
export type LanguageModelV3 = {
  readonly specificationVersion: 'v3';
  readonly provider: string;      // e.g., 'anthropic.messages'
  readonly modelId: string;       // e.g., 'claude-3-haiku-20240307'

  // URL patterns the model can accept natively
  supportedUrls:
    | PromiseLike<Record<string, RegExp[]>>
    | Record<string, RegExp[]>;

  // Non-streaming generation
  doGenerate(
    options: LanguageModelV3CallOptions,
  ): PromiseLike<LanguageModelV3GenerateResult>;

  // Streaming generation
  doStream(
    options: LanguageModelV3CallOptions,
  ): PromiseLike<LanguageModelV3StreamResult>;
};
```

---

### 10. **Model Options Pattern**

**File**: `/packages/anthropic/src/anthropic-messages-options.ts`

Providers define options using **Zod schemas**:

```typescript
import { z } from 'zod/v4';

// 1. Model ID type (union of supported models + generic string)
export type AnthropicMessagesModelId = 
  | 'claude-3-haiku-20240307'
  | 'claude-opus-4-5'
  | (string & {});  // Allow custom models while providing autocomplete

// 2. Zod schema for runtime validation
export const anthropicLanguageModelOptions = z.object({
  sendReasoning: z.boolean().optional(),
  thinking: z.discriminatedUnion('type', [
    z.object({ type: z.literal('adaptive') }),
    z.object({ type: z.literal('enabled'), budgetTokens: z.number() }),
    z.object({ type: z.literal('disabled') }),
  ]).optional(),
  disableParallelToolUse: z.boolean().optional(),
  // ... more options
});

// 3. TypeScript type from schema
export type AnthropicLanguageModelOptions = z.infer<
  typeof anthropicLanguageModelOptions
>;
```

---

### 11. **File Structure Summary**

| File | Purpose |
|------|---------|
| `package.json` | Package metadata, exports, dependencies, scripts |
| `tsconfig.json` | TypeScript compilation for type checking |
| `tsconfig.build.json` | Stripped version for build tool (tsup) |
| `tsup.config.ts` | Build configuration (outputs, formats) |
| `src/index.ts` | Public API exports |
| `src/*-provider.ts` | Factory function + interface definitions |
| `src/*-language-model.ts` | LanguageModelV3 implementation |
| `src/*-options.ts` | Model IDs and Zod validation schemas |
| `src/*-api.ts` | API response type definitions |
| `src/*-error.ts` | Error handling |
| `src/tool/` | Tool/function calling implementation |
| `src/internal/index.ts` | Advanced/internal APIs |
| `vitest.*.config.js` | Test configuration |

---

### 12. **Key Dependencies**

Every provider depends on:

```json
{
  "@ai-sdk/provider": "workspace:*",      // Core ProviderV3, LanguageModelV3
  "@ai-sdk/provider-utils": "workspace:*" // Helper functions:
                                           // - loadApiKey()
                                           // - withUserAgentSuffix()
                                           // - generateId()
                                           // - postJsonToApi()
                                           // - FetchFunction type
}
```

---

### 13. **Comparison: OpenAI Provider Structure**

OpenAI is more complex with **multiple model types**:

```
/packages/openai/src/
├── index.ts                    # Exports
├── openai-provider.ts         # Factory function
├── openai-config.ts           # Settings
├── chat/
│   ├── openai-chat-language-model.ts    # Chat implementation
│   ├── openai-chat-options.ts           # Chat model IDs
│   └── ...
├── completion/
│   ├── openai-completion-language-model.ts
│   ├── openai-completion-options.ts
│   └── ...
├── embedding/
│   ├── openai-embedding-model.ts        # EmbeddingModelV3
│   ├── openai-embedding-options.ts
│   └── ...
├── image/
│   ├── openai-image-model.ts            # ImageModelV3
│   ├── openai-image-options.ts
│   └── ...
├── speech/                              # SpeechModelV3
├── transcription/                       # TranscriptionModelV3
└── responses/
```

**OpenAI Provider Interface**:
```typescript
export interface OpenAIProvider extends ProviderV3 {
  (modelId: OpenAIResponsesModelId): LanguageModelV3;

  languageModel(modelId: OpenAIResponsesModelId): LanguageModelV3;
  chat(modelId: OpenAIChatModelId): LanguageModelV3;
  completion(modelId: OpenAICompletionModelId): LanguageModelV3;
  responses(modelId: OpenAIResponsesModelId): LanguageModelV3;

  embedding(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
  embeddingModel(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;

  image(modelId: OpenAIImageModelId): ImageModelV3;
  imageModel(modelId: OpenAIImageModelId): ImageModelV3;

  transcription(modelId: OpenAITranscriptionModelId): TranscriptionModelV3;
  speech(modelId: OpenAISpeechModelId): SpeechModelV3;

  tools: typeof openaiTools;
}
```

---

### 14. **Internal APIs Export Pattern**

**src/internal/index.ts**:
```typescript
// Re-export internal/advanced APIs
export { AnthropicMessagesLanguageModel } from '../anthropic-messages-language-model';
export { anthropicTools } from '../anthropic-tools';
export type { AnthropicMessagesModelId } from '../anthropic-messages-options';
export { prepareTools } from '../anthropic-prepare-tools';
```

**internal.d.ts** (root):
```typescript
export * from './dist/internal';
```

**This allows**:
```typescript
// Public API
import { anthropic } from '@ai-sdk/anthropic';

// Internal APIs (for advanced use)
import { prepareTools } from '@ai-sdk/anthropic/internal';
```

---

### 15. **Build Output**

Running `npm run build` with tsup produces:

```
dist/
├── index.js              (CommonJS)
├── index.mjs             (ESM)
├── index.d.ts            (Types)
├── internal/
│   ├── index.js
│   ├── index.mjs
│   └── index.d.ts
└── *.map                 (Source maps)
```

---

## Summary: Essential Pattern for New Providers

To add a new provider, follow this template:

1. **Create package structure**: `/packages/<provider>/src/`
2. **Define model types**: `<provider>-messages-options.ts` with union types + Zod
3. **Implement factory**: `<provider>-provider.ts` with `create<Provider>()` function
4. **Implement models**: `<provider>-messages-language-model.ts` extending LanguageModelV3
5. **Export publicly**: `src/index.ts` with selective re-exports
6. **Add config files**: `package.json`, `tsconfig.json`, `tsup.config.ts`
7. **Test both**: Node.js and Edge/browser environments

The provider pattern is **simple but extensible**: a factory function returning an object that is both callable and has methods, implementing the ProviderV3 interface contract.

