  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /** API key. Defaults to `PIXELART_API_KEY` env var. */
  apiKey?: string;
  /** Override the base URL. Defaults to `https://api.pixelart.ai/v1`. */
  baseURL?: string;
  /** Extra headers to include in every request. */
  headers?: Record<string, string>;
  /** Custom fetch implementation for testing or middleware. */
  fetch?: FetchFunction;
}

