### Step 2 — `packages/pixelart/src/pixelart-image-model.ts`

Implements `ImageModelV3`. The fictional API is modeled as a simple synchronous
`POST /images/generations` endpoint that returns base64-encoded images — the
same pattern as OpenAI DALL-E. Provider options are validated with Zod via
`parseProviderOptions`.

Key design decisions:
- `maxImagesPerCall = 1` (conservative default for a fictional provider)
- Returns images as `string` (base64) — avoid unnecessary conversion
- `size` and `aspectRatio` are both accepted; `aspectRatio` is reported as
  unsupported (fictional API only supports fixed sizes)
- `seed` is reported as unsupported
- Error handler uses `createJsonErrorResponseHandler` with a simple schema

```typescript
import {
  ImageModelV3,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support `aspectRatio`. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support the `seed` option.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(size != null ? { size } : {}),
        ...(pixelartOptions?.style != null
          ? { style: pixelartOptions.style }
          : {}),
        ...(pixelartOptions?.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity }
          : {}),
      },
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: data => data.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// ─── Response schema ─────────────────────────────────────────────────────────

const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// ─── Error schema ─────────────────────────────────────────────────────────────

const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

// ─── Provider options schema ──────────────────────────────────────────────────

/**
 * Zod schema for PixelArt provider-specific image generation options.
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * Style preset controlling the visual look of the generated image.
         */
        style: z.enum(['pixel', 'retro', '8bit']).optional(),

        /**
         * Pixel density (pixels-per-unit) for the output image.
         */
        pixelDensity: z.number().positive().optional(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;
```

